import{_ as e,o as a,i as r,ad as s}from"./chunks/framework.By85nKlP.js";const u=JSON.parse('{"title":"Benchmarks","description":"csv-pipe is the fastest common CSV parser, and matches or beats the other libraries at encoding.","frontmatter":{"description":"csv-pipe is the fastest common CSV parser, and matches or beats the other libraries at encoding."},"headers":[],"relativePath":"guide/benchmarks.md","filePath":"guide/benchmarks.md","lastUpdated":1782152596000}'),d={name:"guide/benchmarks.md"};function n(i,t,o,h,c,p){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h1><p>csv-pipe is the fastest of the common CSV libraries at parsing, by a wide margin, and the fastest or on par at encoding, across every dataset tested.</p><p>Throughput is in operations per second, where one operation encodes or parses the whole dataset (higher is better). On the large dataset that is roughly 7M rows/s for encoding and 10M rows/s for parsing. These are indicative numbers from one dev machine; they vary by hardware. Reproduce them with <code>npm run bench</code>.</p><h2 id="how-it-is-measured" tabindex="-1">How it is measured <a class="header-anchor" href="#how-it-is-measured" aria-label="Permalink to &quot;How it is measured&quot;">​</a></h2><p>Each comparison uses the current major of every library (papaparse 5, csv-parse 7, csv-stringify 6, fast-csv 5) on the same data, with headers on and no type coercion, so the libraries do equivalent work. fast-csv is measured through its streaming API, since it has no synchronous one. The harness is <a href="https://github.com/tinylibs/tinybench" target="_blank" rel="noreferrer">tinybench</a> through Vitest, with warmup and repeated samples.</p><h2 id="encoding" tabindex="-1">Encoding <a class="header-anchor" href="#encoding" aria-label="Permalink to &quot;Encoding&quot;">​</a></h2><p>Objects to CSV text, against papaparse, csv-stringify, and fast-csv.</p><table tabindex="0"><thead><tr><th>Dataset</th><th>csv-pipe</th><th>papaparse</th><th>csv-stringify</th><th>fast-csv</th></tr></thead><tbody><tr><td>small (1,000 x 3)</td><td>9,080</td><td>5,470</td><td>5,320</td><td>1,820</td></tr><tr><td>wide (1,000 x 20)</td><td>1,130</td><td>737</td><td>778</td><td>653</td></tr><tr><td>large (50,000 x 3)</td><td>144</td><td>99</td><td>69</td><td>30</td></tr><tr><td>quote-heavy (5k x 3)</td><td>904</td><td>898</td><td>570</td><td>303</td></tr></tbody></table><p>On encoding, csv-pipe runs about 1.5x faster than papaparse and csv-stringify, and up to roughly 5x faster than fast-csv. On quote-heavy data it is about on par with papaparse, and still ahead of csv-stringify and fast-csv.</p><h2 id="parsing" tabindex="-1">Parsing <a class="header-anchor" href="#parsing" aria-label="Permalink to &quot;Parsing&quot;">​</a></h2><p>CSV text to records, against papaparse, csv-parse, and fast-csv.</p><table tabindex="0"><thead><tr><th>Dataset</th><th>csv-pipe</th><th>papaparse</th><th>csv-parse</th><th>fast-csv</th></tr></thead><tbody><tr><td>small (1,000 x 3)</td><td>13,100</td><td>2,960</td><td>1,910</td><td>870</td></tr><tr><td>wide (1,000 x 20)</td><td>1,460</td><td>524</td><td>269</td><td>177</td></tr><tr><td>large (50,000 x 3)</td><td>201</td><td>61</td><td>32</td><td>16</td></tr><tr><td>quote-heavy (5k x 3)</td><td>1,550</td><td>377</td><td>248</td><td>134</td></tr></tbody></table><p>On parsing, csv-pipe runs about 2.8x to 4.4x faster than papaparse, 5x to 7x faster than csv-parse, and 8x to 15x faster than fast-csv.</p><h2 id="why-it-is-fast" tabindex="-1">Why it is fast <a class="header-anchor" href="#why-it-is-fast" aria-label="Permalink to &quot;Why it is fast&quot;">​</a></h2><ul><li>A single pass over the input with <code>charCodeAt</code>, no regular expressions on the hot path.</li><li>Fields are taken as string slices by index, so clean values do no per-character work.</li><li>Options are resolved once per encoder or parser, so repeated calls pay no setup cost.</li></ul><h2 id="tracked-over-time" tabindex="-1">Tracked over time <a class="header-anchor" href="#tracked-over-time" aria-label="Permalink to &quot;Tracked over time&quot;">​</a></h2><p>Encode and parse throughput are measured on every push to <code>master</code> and published to a <a href="https://martsinlabs.github.io/csv-pipe/bench/" target="_blank" rel="noreferrer">live chart</a>. A pull request that regresses past the alert threshold fails the run, so a slowdown cannot land unnoticed.</p>',17)])])}const m=e(d,[["render",n]]);export{u as __pageData,m as default};
